# .github/workflows/create-blocker-issue.yml
name: Create Release Blocker Issue

on:
  workflow_run:
    workflows: ["Claude CI"]
    types: [completed]

jobs:
  create-issue:
    if: github.event.workflow_run.conclusion == 'failure'
    runs-on: ubuntu-latest
    steps:
      - uses: actions/github-script@v7
        with:
          script: |
            // Only create an issue for blocking criterion failures
            const { data: jobs } = await github.rest.actions.listJobsForWorkflowRun({
              owner: context.repo.owner,
              repo: context.repo.repo,
              run_id: context.payload.workflow_run.id,
            });

            const blockerJobs = jobs.jobs.filter(j =>
              j.conclusion === 'failure' &&
              ['prompt-gates', 'staging-gates'].includes(j.name)
            );

            if (blockerJobs.length === 0) return;

            const title = `[Release Blocker] ${blockerJobs.map(j => j.name).join(', ')} failed on ${context.payload.workflow_run.head_sha.slice(0,8)}`;
            await github.rest.issues.create({
              owner: context.repo.owner,
              repo: context.repo.repo,
              title,
              body: `## Release Blocker\n\nCI gate(s) failed: ${blockerJobs.map(j => j.name).join(', ')}\n\nRun: ${context.payload.workflow_run.html_url}\n\nThis issue must be resolved and closed before this SHA can be promoted to staging.`,
              labels: ['release-blocker'],
              assignees: [context.payload.workflow_run.triggering_actor.login],
            });
